import * as fs from 'fs';
import * as path from 'path';

const formalPath = path.join(process.cwd(), 'open-source/aeon/FORMAL_LEDGER.md');
const theoremPath = path.join(process.cwd(), 'open-source/gnosis/THEOREM_LEDGER.md');

const formalText = fs.readFileSync(formalPath, 'utf8');
const theoremText = fs.readFileSync(theoremPath, 'utf8');

const map = new Map<string, string[]>();
let cur = '';

for (const line of formalText.split('\n')) {
  if (line.startsWith('## ') || line.startsWith('### ')) {
    cur = line;
    map.set(cur, []);
  } else if (cur) {
    map.get(cur)?.push(line);
  }
}

const missing = [];
const missingNames = [];
for (const [sec, lines] of map.entries()) {
  if (!theoremText.includes(sec.trim())) {
    missing.push(sec + '\n' + lines.join('\n'));
    missingNames.push(sec.trim());
  }
}

console.log('Missing sections:', missingNames.length);
if (missing.length > 0) {
  fs.appendFileSync(theoremPath, '\n\n' + missing.join('\n\n') + '\n');
  console.log('Appended to THEOREM_LEDGER.md');
}
